/bin/zsh -lc "git status --short
./.venv/bin/python -c 'from sympy import Tuple, lambdify; from sympy.printing.pycode import PythonCodePrinter; from sympy.printing.lambdarepr import LambdaPrinter, lambdarepr; from sympy.utilities.lambdify import _recursive_to_string, lambdastr; cases=[(\"empty\",()),(\"singleton\",(1,)),(\"pair\",(1,2)),(\"nested_singleton\",((1,),)),(\"singleton_empty\",((),)),(\"single_pair\",((1,2),)),(\"mixed_nested\",(1,(2,))), (\"list_single_tuple\",[(1,)])]; pp=PythonCodePrinter(); lp=LambdaPrinter(); print(\"name | pyprinter | lambdaprinter | recursive(lp) | lambdastr body/type | lambdify type/value\");
for n,e in cases:
 vals=[]
 for f in (pp.doprint,lp.doprint,lambda x:_recursive_to_string(lp.doprint,x)):
  try: vals.append(f(e))
  except Exception as ex: vals.append(type(ex).__name__+\":\"+str(ex))
 try: vals.append(lambdastr([],e))
 except Exception as ex: vals.append(type(ex).__name__+\":\"+str(ex))
 try:
  v=lambdify([],e)(); vals.append(type(v).__name__+\":\"+repr(v))
 except Exception as ex: vals.append(type(ex).__name__+\":\"+str(ex))
 print(n,\" | \",\" | \".join(vals))
print(\"SYMPY TUPLES\")
for e in [Tuple(),Tuple(1),Tuple(1,2),Tuple(Tuple(1))]:
 print(repr(e), pp.doprint(e), lp.doprint(e), _recursive_to_string(lp.doprint,e), type(lambdify([],e)()).__name__,repr(lambdify([],e)()))'"

